int64_t bubble_sort_checksum(const int64_t *a, int64_t n) {
    int64_t buf[256];
    for (int64_t i = 0; i < n; i++) buf[i] = a[i];
    for (int64_t i = 0; i < n; i++)
        for (int64_t j = 0; j + 1 + i < n; j++)
            if (buf[j] > buf[j + 1]) {
                int64_t t = buf[j]; buf[j] = buf[j + 1]; buf[j + 1] = t;
            }
    int64_t sum = 0;
    for (int64_t i = 0; i < n; i++) sum += i * buf[i];
    return sum;
}

C++.source:
std::int64_t bubble_sort_checksum(const std::int64_t *a, std::int64_t n) {
    std::vector<std::int64_t> buf(a, a + n);
    for (std::int64_t i = 0; i < n; i++)
        for (std::int64_t j = 0; j + 1 + i < n; j++)
            if (buf[j] > buf[j + 1]) std::swap(buf[j], buf[j + 1]);
    std::int64_t sum = 0;
    for (std::int64_t i = 0; i < n; i++) sum += i * buf[i];
    return sum;
}

Rust.source:
fn bubble_sort_checksum(a: &[i64], n: i64) -> i64 {
    let mut buf = a[..n as usize].to_vec();
    for i in 0..n as usize {
        for j in 0..(n as usize - 1 - i) {
            if buf[j] > buf[j + 1] { buf.swap(j, j + 1); }
        }
    }
    let mut sum = 0;
    for i in 0..n as usize { sum += i as i64 * buf[i]; }
    sum
}

Python.source:
def bubble_sort_checksum(a: list, n: int) -> int:
    buf = a[:n]
    for i in range(n):
        for j in range(n - 1 - i):
            if buf[j] > buf[j + 1]:
                buf[j], buf[j + 1] = buf[j + 1], buf[j]
    return sum(i * buf[i] for i in range(n))

