int64_t second_largest(const int64_t *a, int64_t n) {
    int64_t first = a[0], second = a[1];
    if (second > first) { int64_t t = first; first = second; second = t; }
    for (int64_t i = 2; i < n; i++) {
        if (a[i] > first) { second = first; first = a[i]; }
        else if (a[i] > second) second = a[i];
    }
    return second;
}

C++.source:
std::int64_t second_largest(const std::int64_t *a, std::int64_t n) {
    std::int64_t first = a[0], second = a[1];
    if (second > first) std::swap(first, second);
    for (std::int64_t i = 2; i < n; i++) {
        if (a[i] > first) { second = first; first = a[i]; }
        else if (a[i] > second) second = a[i];
    }
    return second;
}

Rust.source:
fn second_largest(a: &[i64], n: i64) -> i64 {
    let (mut first, mut second) = (a[0], a[1]);
    if second > first { std::mem::swap(&mut first, &mut second); }
    for i in 2..n as usize {
        if a[i] > first { second = first; first = a[i]; }
        else if a[i] > second { second = a[i]; }
    }
    second
}

