def second_largest(a: list, n: int) -> int:
    first, second = a[0], a[1]
    if second > first:
        first, second = second, first
    for i in range(2, n):
        if a[i] > first:
            second, first = first, a[i]
        elif a[i] > second:
            second = a[i]
    return second

