int64_t zeller_dow(int64_t y, int64_t m, int64_t d) {
    if (m < 3) { m += 12; y -= 1; }
    int64_t k = y % 100;
    int64_t j = y / 100;
    int64_t h = (d + 13 * (m + 1) / 5 + k + k / 4 + j / 4 + 5 * j) % 7;
    return (h + 6) % 7;
}

