int64_t luhn_from_array(const int64_t *a, int64_t n) {
    int64_t sum = 0;
    for (int64_t i = 0; i < n; i++) {
        int64_t d = a[n - 1 - i];
        if (i % 2 == 1) {
            d = d * 2;
            if (d > 9) d = d - 9;
        }
        sum += d;
    }
    return sum % 10 == 0 ? 1 : 0;
}

