i64 eval_rpn(const i64 *tokens, i64 n) {
    if (n == 0) return 0;
    i64 stack[256];
    i64 sp = 0;
    for (i64 i = 0; i < n; i++) {
        i64 t = tokens[i];
        if (t >= 0) {
            stack[sp++] = t;
        } else {
            i64 a = stack[sp - 2], b = stack[sp - 1];
            sp -= 2;
            i64 op = -t, r = 0;
            if (op == 1) r = a + b;
            else if (op == 2) r = a - b;
            else if (op == 3) r = a * b;
            else r = a / b;
            stack[sp++] = r;
        }
    }
    return stack[0];
}

