i64 eval_rpn(const i64 *tokens, i64 n) {
    if (n == 0) return 0;
    std::vector<i64> stack;
    stack.reserve(static_cast<size_t>(n));
    for (i64 i = 0; i < n; i++) {
        i64 t = tokens[i];
        if (t >= 0) {
            stack.push_back(t);
        } else {
            i64 b = stack.back(); stack.pop_back();
            i64 a = stack.back(); stack.pop_back();
            i64 op = -t, r = 0;
            if (op == 1) r = a + b;
            else if (op == 2) r = a - b;
            else if (op == 3) r = a * b;
            else r = a / b;
            stack.push_back(r);
        }
    }
    return stack[0];
}

