    for &t in &tokens[..n as usize] {
        if t >= 0 {
            stack.push(t);
        } else {
            let b = stack.pop().unwrap();
            let a = stack.pop().unwrap();
            let r = match -t {
                1 => a + b,
                2 => a - b,
                3 => a * b,
                _ => a / b,
            };
            stack.push(r);
        }
    }
    stack[0]
}

