i64 hex_to_int(const char *s) {
    size_t n = strlen(s);
    if (n == 0) return -1;
    i64 val = 0;
    for (size_t i = 0; i < n; i++) {
        char c = s[i];
        i64 d = -1;
        if (c >= '0' && c <= '9') d = c - '0';
        else if (c >= 'a' && c <= 'f') d = c - 'a' + 10;
        else if (c >= 'A' && c <= 'F') d = c - 'A' + 10;
        if (d < 0) return -1;
        val = val * 16 + d;
    }
    return val;
}

