i64 parse_int_signed(const char *s) {
    size_t n = strlen(s);
    if (n == 0) return 0;
    int neg = 0;
    size_t start = 0;
    if (s[0] == '-') { neg = 1; start = 1; }
    if (start == n) return 0;
    i64 val = 0;
    for (size_t i = start; i < n; i++) {
        char c = s[i];
        if (c < '0' || c > '9') return 0;
        val = val * 10 + (c - '0');
    }
    return neg ? -val : val;
}

