    let (neg, start) = if b[0] == b'-' { (true, 1) } else { (false, 0) };
    if start == b.len() {
        return 0;
    }
    let mut val: i64 = 0;
    for &c in &b[start..] {
        if !c.is_ascii_digit() {
            return 0;
        }
        val = val * 10 + (c - b'0') as i64;
    }
    if neg {
        -val
    } else {
        val
    }
}

