    neg = s[0] == "-"
    start = 1 if neg else 0
    if start == len(s):
        return 0
    val = 0
    for c in s[start:]:
        if not ("0" <= c <= "9"):
            return 0
        val = val * 10 + (ord(c) - 48)
    return -val if neg else val

