typedef long long i64;
i64 luhn_check(const i64 *digits, i64 n) {
    i64 sum = 0;
    for (i64 i = 0; i < n; i++) {
        i64 d = digits[i];
        i64 pos = n - 1 - i;
        if (pos % 2 == 1) {
            d *= 2;
            if (d > 9) d -= 9;
        }
        sum += d;
    }
    return sum % 10 == 0 ? 1 : 0;
}

